const rawItems = $input.all();
const inputData = rawItems.map(item => item.json);

const curveIndexMap = {
  video_2s_watched: 2, 
  video_view: 3, 
  video_10s_watched: 10,
  video_15s_watched: 15,
  video_30s_watched: 18,
  video_60s_watched: 21
};

function extractVideoWatchMetrics(curveValues, totalViews) {
  const metrics = {};
  const total = Number(totalViews) || 0;

  Object.entries(curveIndexMap).forEach(([key, idx]) => {
    if (Array.isArray(curveValues) && idx < curveValues.length) {
      const pct = Number(curveValues[idx]) || 0;
      metrics[key] = Math.round((pct / 100) * total);
    } else {
      metrics[key] = 0;
    }
  });

  return metrics;
}

function processVideoData(data) {
  return data.map(item => {
    const result = {
      account_id: item.account_id,
      campaign_id: item.campaign_id,
      adset_id: item.adset_id,
      ad_id: item.ad_id,
      objective: item.objective,
      optimization_goal: item.optimization_goal,
      date_start: item.date_start,
      date_stop: item.date_stop,
      video_play: 0,
      video_2s_watched: 0,
      video_view: 0,
      video_10s_watched: 0,
      video_15s_watched: 0,
      video_30s_watched: 0,
      video_60s_watched: 0
    };

    if (Array.isArray(item.video_play_actions)) {
      const vidAction = item.video_play_actions.find(a => a.action_type === 'video_view');
      if (vidAction) {
        result.video_play = Number(vidAction.value) || 0;
      }
    }

    if (Array.isArray(item.video_play_curve_actions)) {
      const curveAction = item.video_play_curve_actions.find(a => a.action_type === 'video_view');
      const curveValues = Array.isArray(curveAction?.value) ? curveAction.value : [];
      Object.assign(result, extractVideoWatchMetrics(curveValues, result.video_play));
    }

    return result;
  });
}

const finalResult = processVideoData(inputData).map(item => ({ json: item }));
return finalResult;

